import * as React from 'react';
import AppBar from '@mui/material/AppBar';
import Box from '@mui/material/Box';
import Toolbar from '@mui/material/Toolbar';
import Typography from '@mui/material/Typography';
import Button from '@mui/material/Button';
import IconButton from '@mui/material/IconButton';
import MenuIcon from '@mui/icons-material/Menu';
import Link from "@mui/material/Link"
import {Grid} from "@mui/material"

export default function Barra() {
  return (
    <Box sx={{ flexGrow: 1}}>
      <AppBar sx={{bgcolor:"warning.main"}} position="static">
        <Toolbar>
          <IconButton
            size="large"
            edge="start"
            color="inherit"
            aria-label="menu"
            sx={{ mr: 2 }}
          >
            <MenuIcon />
          </IconButton>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1 }}>
            <Link href="#" variant='h5'>NombreDeMarca</Link>
          </Typography>
          <Grid container spacing={2} sx={{display:"flex", flexDirection:"row"}}>
            <Grid item>
              <Link href="#" color="inherit" underline='hover' variant='body2'>Quiénes somos?</Link>
            </Grid>
            <Grid item>
              <Link href="#" color="inherit" underline='hover' variant='body2'>Nuestro trabajo</Link>
            </Grid>
            <Grid item>
              <Link href="#" color="inherit" underline='hover' variant='body2'>Preguntas frecuentes</Link>
            </Grid>
          </Grid>
          <Button color="inherit">Iniciar sesión</Button>
          <Button color="inherit">Registrarse</Button>
        </Toolbar>
      </AppBar>
    </Box>
  );
}
